	private function annual_plan($data, $ischeck) {
		if ($data['age'] < 30) {
			$idx1 = 0;
		} else if ($data['age'] < 55) {
			$idx1 = 1;
		} else if ($data['age'] < 60) {
			$idx1 = 2;
		} else if ($data['age'] < 65) {
			$idx1 = 3;
		} else if ($data['age'] < 70) {
			$idx1 = 4;
		} else if ($data['age'] < 75) {
			$idx1 = 5;
		} else {
			$this->premiumArr['message'] = 'Annual plan, age must less than 75.';
			$this->premiumArr['active_tab'] = 'date_members_tab';
			return 0;
		}
		
		if (($data['totaldays'] != 365) && ($data['totaldays'] != 366)) {
			$this->premiumArr['message'] = 'Annual plan, the days must be a year long.';
			$this->premiumArr['active_tab'] = 'date_members_tab';
			return 0;
		}
		
		if ($data['isfamilyplan']) {
			$this->premiumArr['message'] = "Annual plan isn't avaliable for family or group.";
			$this->premiumArr['active_tab'] = 'date_members_tab';
			return 0;
		}
		
		if ($ischeck) {
			return 1;
		}
		
		if ($data['annual_plan_days'] == 4) {
			$idx2 = 0;
		} else if ($data['annual_plan_days'] == 9) {
			$idx2 = 1;
		} else if ($data['annual_plan_days'] == 17) {
			$idx2 = 2;
		} else if ($data['annual_plan_days'] == 30) {
			$idx2 = 3;
		} else if ($data['annual_plan_days'] == 60) {
			$idx2 = 4;
		} else {
			$this->premiumArr['message'] = 'Unknow selected days. Please select plan days.';
			$this->premiumArr['active_tab'] = 'packages_tab';
			return 1;
		}
		
		$this->premiumArr['premium'] = $this->annual[$idx2][$idx1];

		if ($this->premiumArr['premium'] > 0) {
			$this->premiumArr['status'] = 'OK';
		}
		return 1;
	}
	
	private function optional_plan($data, $ischeck) {
		$this->premiumArr['trip_cancellation'] = 1;
		if ($ischeck) {
			if ($data['age'] >= 75) {
				$this->premiumArr['trip_cancellation'] = 0;
			}
			if (($data['package'] == 'optional_plan') && $data['isfamilyplan']) {
				$this->premiumArr['message'] = "Trip cancellation is't avaliable for family or group.";
				$this->premiumArr['active_tab'] = 'packages_tab';
				$this->premiumArr['premium'] = 0;
				return 0;
			}
			return 1;
		}

		if (!empty($data['ad_and_d_ck'])) {
			$rate = isset($this->ad_and_d[$data['ad_and_d_insured']]) ? $this->ad_and_d[$data['ad_and_d_insured']] : 0;
			if (empty($rate)) {
				$this->premiumArr['message'] = "Unknown AD & D insured amount. Please select insured amount";
				$this->premiumArr['active_tab'] = 'packages_tab';
				$this->premiumArr['premium'] = 0;
				return 0;
			}

			if ($data['isfamilyplan'] == 1) {
				$rate *= 2.25;
			} else if ($data['isfamilyplan'] == 2) {
				$rate *= $data['people_number'];
			}
			
			$this->premiumArr['premium'] += $rate * $data['totaldays'];
		}
			
		if (!empty($data['flight_accident_ck'])) {
			$rate = isset($this->flight_accident[$data['flight_accident_insured']]) ? $this->flight_accident[$data['flight_accident_insured']] : 0;
			if (empty($rate)) {
				$this->premiumArr['message'] = "Unknown flight accident insured amount. Please select insured amount";
				$this->premiumArr['active_tab'] = 'packages_tab';
				$this->premiumArr['premium'] = 0;
				return 0;
			}
				
			if ($data['isfamilyplan'] == 1) {
				$rate *= 2.25;
			} else if ($data['isfamilyplan'] == 2) {
				$rate *= $data['people_number'];
			}
			
			$this->premiumArr['premium'] += $rate;
		}
		
		if (!empty($data['trip_cancellation_ck'])) {
			$arr = 'trip_cancellation';
			if ($data['age'] < 60) {
				$arr = 'trip_cancellation_0_59';
			} else if ($data['age'] < 65) {
				$arr = 'trip_cancellation_60_64';
			} else if ($data['age'] < 70) {
				$arr = 'trip_cancellation_65_69';
			} else if ($data['age'] < 75) {
				$arr = 'trip_cancellation_70_74';
			}
			if (!isset($this->{$arr}) || !is_array($this->{$arr})) {
				$this->premiumArr['message'] = 'Age must less than 75 for Trip Cancellation plan.';
				$this->premiumArr['active_tab'] = 'packages_tab';
				$this->premiumArr['premium'] = 0;
				return 1;
			}
				
			$idx = $data['trip_cancellation_insured'] / 100;
			if ($idx < 26) {
				$base = $this->{$arr}[$idx];
			} else {
				$base = $this->{$arr}[25] + (($idx - 26) * $this->{$arr}[26]);
			}
			
			if ($data['isfamilyplan'] == 1) {
				$base *= 2.25;
			} else if ($data['isfamilyplan'] == 2) {
				$base *= $data['people_number'];
			}
				
			$this->premiumArr['premium'] += $base;
			
			// Add TAX if needs
			if (($data['province2'] == 'MB') || ($data['province2'] == 'ON')) {
				// 8% TAX
				$this->premiumArr['tax'] += $base * 0.08;
				$this->premiumArr['premium'] += $base * 0.08;
			} else if ($data['province2'] == 'QC') {
				// 9% TAX
				$this->premiumArr['tax'] += $base * 0.09;
				$this->premiumArr['premium'] += $base * 0.09;
			} else if ($data['province2'] == 'SK') {
				// 6% TAX
				$this->premiumArr['tax'] += $base * 0.06;
				$this->premiumArr['premium'] += $base * 0.06;
			}
		}
		
		if ($this->premiumArr['premium'] > 0) {
			$this->premiumArr['status'] = 'OK';
		}

		return 1;
	}
	
	private function single_medical_plan($data, $ischeck) {
		$arr = 'single_medical';
		$mindays = 1;
		$maxdays = 120;
		if ($data['age'] < 30) {
			$arr = 'single_medical_0_29';
		} else if ($data['age'] < 55) {
			$arr = 'single_medical_30_54';
		} else if ($data['age'] < 60) {
			$arr = 'single_medical_55_59';
		} else if ($data['age'] < 65) {
			$arr = 'single_medical_60_64';
			if ($data['isfamilyplan'] || ($data['people_number'] > 1)) {
				$this->premiumArr['message'] = "Single Medical Plan can't include members over 60";
				$this->premiumArr['active_tab'] = 'date_members_tab';
				return 1;
			}
			if ($data['totaldays'] > 60) {
				$mindays = 61;
				$this->premiumArr['questionnaire'] = 1;
				if (empty($data['questionnaire'])) {
					$this->premiumArr['message'] = 'Please fill in questionnaire.';
					$this->premiumArr['active_tab'] = 'questionnaire_tab';
					return 1;
				}
			}
		} else if ($data['age'] < 70) {
			$arr = 'single_medical_65_69';
			if ($data['isfamilyplan'] || ($data['people_number'] > 1)) {
				$this->premiumArr['message'] = "Single Medical Plan can't include members over 60";
				$this->premiumArr['active_tab'] = 'date_members_tab';
				return 1;
			}
			if ($data['totaldays'] > 60) {
				$this->premiumArr['questionnaire'] = 1;
				$mindays = 61;
				if (empty($data['questionnaire'])) {
					$this->premiumArr['message'] = 'Please fill in questionnaire.';
					$this->premiumArr['active_tab'] = 'questionnaire_tab';
					return 1;
				}
			}
		} else if ($data['age'] < 75) {
			$arr = 'single_medical_70_74';
			if ($data['isfamilyplan'] || ($data['people_number'] > 1)) {
				$this->premiumArr['message'] = "Single Medical Plan can't include members over 60";
				$this->premiumArr['active_tab'] = 'date_members_tab';
				return 1;
			}
			if ($data['totaldays'] > 60) {
				$this->premiumArr['questionnaire'] = 1;
				$mindays = 61;
				if (empty($data['questionnaire'])) {
					$this->premiumArr['message'] = 'Please fill in questionnaire.';
					$this->premiumArr['active_tab'] = 'questionnaire_tab';
					return 1;
				}
			}
		} else if ($data['age'] < 80) {
			$arr = 'single_medical_75_79';
			if ($data['isfamilyplan'] || ($data['people_number'] > 1)) {
				$this->premiumArr['message'] = "Single Medical Plan can't include members over 60";
				$this->premiumArr['active_tab'] = 'date_members_tab';
				return 1;
			}
			$this->premiumArr['questionnaire'] = 1;
			$this->premiumArr['stable_condition'] = 1;
			if (empty($data['stable_condition'])) {
				$this->premiumArr['message'] = 'Please select pre-existing condition coverage';
				$this->premiumArr['active_tab'] = 'packages_tab';
				return 1;
			} else if (empty($data['questionnaire'])) {
				$this->premiumArr['message'] = 'Please fill in questionnaire.';
				$this->premiumArr['active_tab'] = 'questionnaire_tab';
				return 1;
			}
			$arr .= '_c'.$data['stable_condition'];
		} else if ($data['age'] < 85) {
			$arr = 'single_medical_80_84';
			if ($data['isfamilyplan'] || ($data['people_number'] > 1)) {
				$this->premiumArr['message'] = "Single Medical Plan can't include members over 60";
				$this->premiumArr['active_tab'] = 'date_members_tab';
				return 1;
			}
			$this->premiumArr['questionnaire'] = 1;
			$this->premiumArr['stable_condition'] = 1;
			if (empty($data['stable_condition'])) {
				$this->premiumArr['message'] = 'Please select pre-existing condition coverage';
				$this->premiumArr['active_tab'] = 'packages_tab';
				return 1;
			} else if (empty($data['questionnaire'])) {
				$this->premiumArr['message'] = 'Please fill in questionnaire.';
				$this->premiumArr['active_tab'] = 'questionnaire_tab';
				return 1;
			}
			$arr .= '_c'.$data['stable_condition'];
		} else {
			$this->premiumArr['message'] = 'Age must less than 85.';
			$this->premiumArr['active_tab'] = 'date_members_tab';
			return 0;
		}
		
		if ($data['questionnaire']) {
			$arr .= "_t".$data['questionnaire'];
		}
		
		if (($data['totaldays'] < $mindays) || ($data['totaldays'] > $maxdays)) {
			$this->premiumArr['message'] = 'Please select days less than 120.';
			$this->premiumArr['active_tab'] = 'date_members_tab';
			return 1;
		}
		
		$dayidx = $data['totaldays'] - $mindays;	// change to index
		
		if (!isset($this->{$arr}) || !is_array($this->{$arr}) || !isset($this->{$arr}[$dayidx])) {
			$this->premiumArr['message'] = 'Out of condition range. Please change days or other conditions';
			return 0;
		}
		
		if ($ischeck) {
			return 1;
		}
		
		$this->premiumArr['premium'] = $this->{$arr}[$dayidx];
		
		if ($data['isfamilyplan'] == 1) {
			$this->premiumArr['premium'] *= 2.25;		// single premium times 2.25
		} else if ($data['isfamilyplan'] == 2) {
			$this->premiumArr['premium'] *= $data['people_number'];
			if ($data['people_number'] > 9) {
				$this->premiumArr['premium'] *= 0.9;	// 10% discount apply if number of members is 10 or more
			}
		}
		
		if ($this->premiumArr['premium'] > 0) {
			return $this->optional_plan($data, 0);
		} else {
			$this->premiumArr['message'] = 'Not available. Please change days or insure amount';
		}

		return 1;
	}
	
	private function all_inclusive($data, $ischeck) {
		$arr = 'all_inclusive';
		$mindays = 1;
		$maxdays = 120;
		if ($data['age'] < 30) {
			$arr = 'all_inclusive_0_29';
		} else if ($data['age'] < 55) {
			$arr = 'all_inclusive_30_54';
		} else if ($data['age'] < 60) {
			$arr = 'all_inclusive_55_59';
		} else if ($data['age'] < 65) {
			$arr = 'all_inclusive_60_64';
			if ($data['totaldays'] > 60) {
				$mindays = 61;
				$this->premiumArr['questionnaire'] = 1;
				if ($data['isfamilyplan']) {
					$this->premiumArr['message'] = "Over 60 years old and more than 60 days can't select group plan.";
					$this->premiumArr['active_tab'] = 'date_members_tab';
					return 0;
				}
				if (empty($data['questionnaire'])) {
					$this->premiumArr['message'] = 'Please fill in questionnaire.';
					$this->premiumArr['active_tab'] = 'questionnaire_tab';
					return 1;
				}
			}
		} else if ($data['age'] < 70) {
			$arr = 'all_inclusive_65_69';
			if ($data['totaldays'] > 60) {
				$this->premiumArr['questionnaire'] = 1;
				$mindays = 61;
				if ($data['isfamilyplan']) {
					$this->premiumArr['message'] = "Over 60 years old and more than 60 days can't select group plan.";
					$this->premiumArr['active_tab'] = 'date_members_tab';
					return 0;
				}
				if (empty($data['questionnaire'])) {
					$this->premiumArr['message'] = 'Please fill in questionnaire.';
					$this->premiumArr['active_tab'] = 'questionnaire_tab';
					return 1;
				}
			}
		} else if ($data['age'] < 75) {
			$arr = 'all_inclusive_70_74';
			if ($data['totaldays'] > 60) {
				$this->premiumArr['questionnaire'] = 1;
				$mindays = 61;
				if ($data['isfamilyplan']) {
					$this->premiumArr['message'] = "Over 60 years old and more than 60 days can't select group plan.";
					$this->premiumArr['active_tab'] = 'date_members_tab';
					return 0;
				}
				if (empty($data['questionnaire'])) {
					$this->premiumArr['message'] = 'Please fill in questionnaire.';
					$this->premiumArr['active_tab'] = 'questionnaire_tab';
					return 1;
				}
			}
		} else if ($data['age'] < 80) {
			$arr = 'all_inclusive_75_79';
			$this->premiumArr['questionnaire'] = 1;
			$this->premiumArr['stable_condition'] = 1;
			if ($data['free_cancel']) {
				$this->premiumArr['message'] = "Age over 75 can't select free cancel plan.";
				$this->premiumArr['active_tab'] = 'packages_tab';
				return 1;
			}
			if ($data['isfamilyplan']) {
				$this->premiumArr['message'] = "Over 75 can't select family or group plan.";
				$this->premiumArr['active_tab'] = 'date_members_tab';
				return 0;
			}
			if (empty($data['questionnaire'])) {
				$this->premiumArr['message'] = 'Please fill in questionnaire.';
				$this->premiumArr['active_tab'] = 'questionnaire_tab';
				return 1;
			} else if (empty($data['stable_condition'])) {
				$this->premiumArr['message'] = 'Please select pre-existing condition coverage';
				$this->premiumArr['active_tab'] = 'packages_tab';
				return 1;
			}
			$arr .= '_c'.$data['stable_condition'];
		} else if ($data['age'] < 85) {
			$arr = 'all_inclusive_80_84';
			$this->premiumArr['questionnaire'] = 1;
			$this->premiumArr['stable_condition'] = 1;
			if ($data['free_cancel']) {
				$this->premiumArr['message'] = "Age over 75 can't select free cancel plan.";
				$this->premiumArr['active_tab'] = 'packages_tab';
				return 1;
			}
			if ($data['isfamilyplan']) {
				$this->premiumArr['message'] = "Over 75 can't select family or group plan.";
				$this->premiumArr['active_tab'] = 'date_members_tab';
				return 0;
			}
			if (empty($data['questionnaire'])) {
				$this->premiumArr['message'] = 'Please fill in questionnaire.';
				$this->premiumArr['active_tab'] = 'questionnaire_tab';
				return 1;
			} else if (empty($data['stable_condition'])) {
				$this->premiumArr['message'] = 'Please select pre-existing condition coverage';
				$this->premiumArr['active_tab'] = 'packages_tab';
				return 1;
			}
			$arr .= '_c'.$data['stable_condition'];
		} else {
			$this->premiumArr['message'] = 'Age must less than 85.';
			$this->premiumArr['active_tab'] = 'date_members_tab';
			return 0;
		}
		
		if ($ischeck) {
			return 1;
		}
		
		if ($data['free_cancel']) {
			$arr .= "_cancel";
		} else if ($data['questionnaire']) {
			$arr .= "_t".$data['questionnaire'];
		}

		if (($data['sum_insured'] < 0) || ($data['sum_insured'] > 15000)) {
			$this->premiumArr['message'] = 'Out of insured amount. Amount must less 15,000';
			$this->premiumArr['active_tab'] = 'packages_tab';
			return 1;
		}
			
		if (($data['totaldays'] < $mindays) || ($data['totaldays'] > $maxdays)) {
			$this->premiumArr['message'] = 'Out of days range. Please check effective date and expiry date';
			$this->premiumArr['active_tab'] = 'date_members_tab';
			return 1;
		}
		
		$dayidx = $data['totaldays'] - $mindays;	// change to index
		$sum_idx = $data['sum_insured'] / 100;
		
		$this->premiumArr['arr'] = $arr;
		
		if (!isset($this->{$arr}) || !is_array($this->{$arr}) || !isset($this->{$arr}[$dayidx][10])) {
			$this->premiumArr['message'] = 'Out of condition range. Please check Days, insured amount and other conditions.';
			return 1;
		}
		if ($sum_idx > 25) {
			$this->premiumArr['premium'] = $this->{$arr}[$dayidx][26] * ($sum_idx - 25) + $this->{$arr}[$dayidx][25];
		} else {
			$this->premiumArr['premium'] = $this->{$arr}[$dayidx][$sum_idx];
		}
		
		if ($this->premiumArr['premium'] > 0) {
			$this->premiumArr['status'] = 'OK';
			if ($data['isfamilyplan'] == 1) {
				$this->premiumArr['premium'] *= 2.25;		// single premium times 2.25
			} else if ($data['isfamilyplan'] == 2) {
				$this->premiumArr['premium'] *= $data['people_number'];
				if ($data['people_number'] > 9) {
					$this->premiumArr['premium'] *= 0.9;	// 10% discount apply if number of members is 10 or more
				}
			}
		
			$this->premiumArr['premium_org'] = $this->premiumArr['premium'];
			// Add TAX if needs
			if (($data['province2'] == 'MB') || ($data['province2'] == 'ON')) {
				// 8% TAX
				$this->premiumArr['tax'] = $this->premiumArr['premium'] * 0.08;
				$this->premiumArr['premium'] += $this->premiumArr['tax'];
			} else if ($data['province2'] == 'QC') {
				// 9% TAX
				$this->premiumArr['tax'] = $this->premiumArr['premium'] * 0.09;
				$this->premiumArr['premium'] += $this->premiumArr['tax'];
			} else if ($data['province2'] == 'SK') {
				// 6% TAX
				$this->premiumArr['tax'] = $this->premiumArr['premium'] * 0.06;
				$this->premiumArr['premium'] += $this->premiumArr['tax'];
			}
		} else {
			$this->premiumArr['message'] = 'Not available. Please adjust insured amount or days';
		}
		
		return 1;
	}
	
	public function get_premium($passdata) {
		$this->premiumArr['all_inclusive'] = $this->all_inclusive($passdata, 1);
		$this->premiumArr['single_medical_plan'] = $this->single_medical_plan($passdata, 1);
		$this->premiumArr['annual_plan'] = $this->annual_plan($passdata, 1);
		$this->premiumArr['optional_plan'] = $this->optional_plan($passdata, 1);
		$this->premiumArr['questionnaire'] = 0;
		$this->premiumArr['stable_condition'] = 0;
		$this->premiumArr['premium'] = 0;
		$this->premiumArr['tax'] = 0;
		$this->premiumArr['totalyears'] = $passdata['age'];
		$this->premiumArr['totaldays'] = $passdata['totaldays'];
		$this->premiumArr['sum_insured'] = $passdata['sum_insured'];
		$this->premiumArr['deductible_amount'] =  0;
		$this->premiumArr['from_top'] =  1;
		$this->premiumArr['status'] = 'Fail';
		$this->premiumArr['message'] = '';
		$this->premiumArr['active_tab'] = '';
		
		if (($passdata['people_number'] > 1) && empty($passdata['isfamilyplan'])) {
			$this->premiumArr['message'] = 'Please select family or group for more than one member';
			$this->premiumArr['active_tab'] = 'date_members_tab';
		} else {
			$package = $passdata['package'];
			if (method_exists($this, $package)) {
				$this->$package($passdata, 0);
			}
			if (($passdata['isfamilyplan'] == 2) && $passdata['questionnaire']) {
				$this->premiumArr['questionnaire'] = 0;
				$this->premiumArr['premium'] = 0;
				$this->premiumArr['status'] = 'Fail';
				$this->premiumArr['message'] = "The oldest age people is over group member conditions";
				$this->premiumArr['active_tab'] = 'date_members_tab';
			}

			if (($this->premiumArr['status'] == 'OK') && ($passdata['isfamilyplan'] == 2)) {
				// Passed check, re-calculate premium
				$premium = 0;
				$tax = 0;
				$people_number = $passdata['people_number'];
				$passdata['people_number'] = 1;
				$passdata['isfamilyplan'] = 0;
				foreach ($passdata['agearr'] as $age) {
					$passdata['age'] = $age;
					$this->premiumArr['premium'] = 0;
					$this->premiumArr['tax'] = 0;
					$this->$package($passdata, 0);
					$premium += $this->premiumArr['premium'];
					$tax += $this->premiumArr['tax'];
				}
				if ($people_number > 9) {
					$premium *= 0.9;	// 10% discount apply if number of members is 10 or more
					$tax *= 0.9;	// 10% discount apply if number of members is 10 or more
				}
				$this->premiumArr['premium'] = $premium; 
				$this->premiumArr['tax'] = $tax; 
			}
				
			if (($this->premiumArr['premium'] > 0) && ($this->premiumArr['premium'] < 25)) {
				$this->premiumArr['premium'] = 25;
			}
		}
		return $this->premiumArr;
	}
	
	public function refund_amount($plan, $days) {
		if (empty($plan) || ($plan['totaldays'] <= $days)) {
			return 0;
		}
		if ($plan['package'] == 'single_medical_plan') {
			$para = array();
			$para['age'] = $plan['totalyears'];
			$para['totaldays'] = 120;
			$para['questionnaire'] = $plan['questionnaire'];
			$para['stable_condition'] = $plan['stable_condition'];
			$para['isfamilyplan'] = $plan['isfamilyplan'];
			$para['people_number'] = 1;
			if ($para['isfamilyplan'] == 2) {
				// Group plan
				$this->load->model('customer_model');
				$this->load->model('product_model');
				
				$para['isfamilyplan'] = 0;
				
				$customer = $this->customer_model->get_customer_by_id($plan['customer_id']);
				$para['age'] = $this->product_model->getYears($plan['effective_date'], $customer['birthday']);
				$this->single_medical_plan($para, 0);
				$premium = $this->premiumArr['premium'];
				$tax = $this->premiumArr['tax'];
				
				$customers = $this->customer_model->get_customer_by_parent_id($plan['customer_id']);
				foreach ($customers as $customer) {
					$para['age'] = $this->product_model->getYears($plan['effective_date'], $customer['birthday']);
					$this->single_medical_plan($para, 0);
					$premium += $this->premiumArr['premium'];
					$tax += $this->premiumArr['tax'];
				}
				$this->premiumArr['premium'] = $premium;
				$this->premiumArr['tax'] = $tax;
			} else {
				$this->single_medical_plan($para, 0);
			}
			if ($this->premiumArr['status'] == 'OK') {
				$refund = $this->premiumArr['premium'] / 120 * ($plan['totaldays'] - $days);
				if ($refund > 0) {
					return $refund;
				}
			}
		}
		return 0;
	}
